#include <iostream>
#include <stack>
#include <string>

using namespace std;

bool isBalanced(string s)
{
    stack<char> openers;

    for (char c : s)
    {
        if (c == '(' || c == '[' || c == '{')
        {
            openers.push(c);
        }
        else if (c == ')' || c == ']' || c == '}')
        {
            if (openers.empty())
            {
                return false; // closer with nothing to match
            }

            char top = openers.top();
            if ((c == ')' && top != '(') ||
                (c == ']' && top != '[') ||
                (c == '}' && top != '{'))
            {
                return false; // WRONG kind of opener at the top
            }
            openers.pop();
        }
    }
    return openers.empty(); // balanced only if every opener was matched
}

int main()
{
    cout << isBalanced("([a+b])") << endl;
    cout << isBalanced("(a+b]") << endl;

    return 0;
}

